import{_ as a,o as i,c as o,aA as t}from"./chunks/framework.CAIZw9CR.js";const u=JSON.parse('{"title":"Concepts index","description":"","frontmatter":{},"headers":[],"relativePath":"concepts_index.md","filePath":"concepts_index.md","lastUpdated":null}'),r={name:"concepts_index.md"};function l(s,e,n,c,p,d){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="Concepts-index" tabindex="-1">Concepts index <a class="header-anchor" href="#Concepts-index" aria-label="Permalink to &quot;Concepts index {#Concepts-index}&quot;">​</a></h1><p>This page maps the concepts that are public in Kraken.jl v0.1.0. It is deliberately narrower than the development branches: if a feature is not listed here, do not assume it is usable from this branch.</p><p>If you are brand new to the package, start with <a href="./getting_started">Getting started</a>, then return here for the theory links.</p><h2 id=".krk-files" tabindex="-1"><code>.krk</code> files <a class="header-anchor" href="#.krk-files" aria-label="Permalink to &quot;`.krk` files {#.krk-files}&quot;">​</a></h2><p>A <code>.krk</code> file is the primary user-facing description of a simulation: domain, physics, boundaries, initial conditions, outputs and diagnostics live in one small text file.</p><ul><li><p>Reference: <a href="./krk/overview">.krk overview</a>, <a href="./krk/directives">Directives</a></p></li><li><p>Example: <a href="./examples/10_krk_config">.krk configuration</a></p></li></ul><h2 id="Lattices-and-equilibrium" tabindex="-1">Lattices and equilibrium <a class="header-anchor" href="#Lattices-and-equilibrium" aria-label="Permalink to &quot;Lattices and equilibrium {#Lattices-and-equilibrium}&quot;">​</a></h2><p>LBM evolves discrete populations <code>f_i(x, t)</code> on a finite set of velocities. Kraken uses D2Q9 in 2D and D3Q19 in 3D. Equilibrium is a low-Mach expansion that recovers incompressible Navier-Stokes in the hydrodynamic limit.</p><ul><li><p>Theory: <a href="./theory/01_lbm_fundamentals">LBM fundamentals</a>, <a href="./theory/02_d2q9_lattice">D2Q9 lattice</a>, <a href="./theory/06_from_2d_to_3d">From 2D to 3D</a></p></li><li><p>Examples: <a href="./examples/01_poiseuille_2d">Poiseuille 2D</a>, <a href="./examples/05_cavity_3d">Lid-driven cavity 3D</a></p></li></ul><h2 id="BGK-collision" tabindex="-1">BGK collision <a class="header-anchor" href="#BGK-collision" aria-label="Permalink to &quot;BGK collision {#BGK-collision}&quot;">​</a></h2><p>BGK is the public collision model in this branch. The relaxation parameter sets the kinematic viscosity, and the same conceptual model is used in 2D and 3D.</p><ul><li><p>Theory: <a href="./theory/03_bgk_collision">BGK collision</a></p></li><li><p>Examples: <a href="./examples/04_cavity_2d">Lid-driven cavity 2D</a>, <a href="./examples/03_taylor_green_2d">Taylor-Green vortex</a></p></li></ul><h2 id="Streaming" tabindex="-1">Streaming <a class="header-anchor" href="#Streaming" aria-label="Permalink to &quot;Streaming {#Streaming}&quot;">​</a></h2><p>Streaming shifts post-collision populations to neighboring nodes along each lattice direction. This is the non-local part of each LBM step.</p><ul><li><p>Theory: <a href="./theory/04_streaming">Streaming</a></p></li><li><p>Examples: <a href="./examples/02_couette_2d">Couette flow</a>, <a href="./examples/01_poiseuille_2d">Poiseuille 2D</a></p></li></ul><h2 id="Boundary-conditions" tabindex="-1">Boundary conditions <a class="header-anchor" href="#Boundary-conditions" aria-label="Permalink to &quot;Boundary conditions {#Boundary-conditions}&quot;">​</a></h2><p>The public boundary set covers bounce-back walls, Zou-He velocity/pressure forms, periodic axes, and scalar fixed-temperature walls for thermal runs. Spatial expressions are supported on selected 2D velocity/pressure paths.</p><ul><li><p>Theory: <a href="./theory/05_boundary_conditions">Boundary conditions</a>, <a href="./theory/19_spatial_bcs">Spatial BCs</a></p></li><li><p>Reference: <a href="./krk/bc_types">BC types</a></p></li><li><p>Examples: <a href="./examples/06_cylinder_2d">Cylinder 2D</a>, <a href="./examples/07_heat_conduction">Heat conduction</a></p></li></ul><h2 id="Body-forces" tabindex="-1">Body forces <a class="header-anchor" href="#Body-forces" aria-label="Permalink to &quot;Body forces {#Body-forces}&quot;">​</a></h2><p>Guo forcing is used for body-force-driven channels and for Boussinesq thermal coupling.</p><ul><li><p>Theory: <a href="./theory/07_body_forces">Body forces</a></p></li><li><p>Examples: <a href="./examples/01_poiseuille_2d">Poiseuille 2D</a>, <a href="./examples/08_rayleigh_benard">Rayleigh-Benard convection</a></p></li></ul><h2 id="Thermal-coupling" tabindex="-1">Thermal coupling <a class="header-anchor" href="#Thermal-coupling" aria-label="Permalink to &quot;Thermal coupling {#Thermal-coupling}&quot;">​</a></h2><p>The thermal model uses a second distribution function for temperature. The temperature field can be passive or coupled back to the velocity field through Boussinesq buoyancy.</p><ul><li><p>Theory: <a href="./theory/08_thermal_ddf">Thermal DDF</a></p></li><li><p>Examples: <a href="./examples/07_heat_conduction">Heat conduction</a>, <a href="./examples/08_rayleigh_benard">Rayleigh-Benard convection</a></p></li></ul><h2 id="Outputs-and-post-processing" tabindex="-1">Outputs and post-processing <a class="header-anchor" href="#Outputs-and-post-processing" aria-label="Permalink to &quot;Outputs and post-processing {#Outputs-and-post-processing}&quot;">​</a></h2><p>Kraken writes VTK/PVD files for ParaView and can produce image/GIF outputs through the CairoMakie extension. Post-processing helpers extract lines, probe fields and compute error metrics.</p><ul><li>API: <a href="./api/io">IO</a>, <a href="./api/postprocess">Postprocess</a></li></ul><h2 id="Explicitly-not-public-here" tabindex="-1">Explicitly not public here <a class="header-anchor" href="#Explicitly-not-public-here" aria-label="Permalink to &quot;Explicitly not public here {#Explicitly-not-public-here}&quot;">​</a></h2><p>MRT, axisymmetric LBM, grid refinement, VOF, phase-field, Shan-Chen, species transport, rheology, viscoelasticity and SLBM/body-fitted work are not public features of this branch. Some are present in other branches, especially <code>slbm-paper</code>, but they require their own validation and documentation pass.</p><p>See <a href="./capabilities">Capabilities</a> for the precise status matrix.</p>',30)])])}const f=a(r,[["render",l]]);export{u as __pageData,f as default};
